import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { validateRequestUser } from '@/lib/auth-server';
import { validateItemInput } from '@/lib/validation';
import { broadcastUpdate } from '@/lib/events';

export const dynamic = 'force-dynamic';

// PUT /api/items/[id] - Edit an item
export async function PUT(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    // 1. Authenticate user
    const user = await validateRequestUser(req);
    if (!user) {
      return NextResponse.json(
        { error: 'Unauthorized. Please log in first.' },
        { status: 401 }
      );
    }

    // 2. Check if item exists
    const existingItem = await prisma.item.findUnique({
      where: { id },
    });

    if (!existingItem) {
      return NextResponse.json(
        { error: 'Item not found.' },
        { status: 404 }
      );
    }

    // 3. Parse and validate body
    const body = await req.json().catch(() => ({}));
    const { error, validatedData } = validateItemInput(body);

    if (error || !validatedData) {
      return NextResponse.json({ error }, { status: 400 });
    }

    // 4. Update the item
    const updatedItem = await prisma.item.update({
      where: { id },
      data: {
        name: validatedData.name,
        category: validatedData.category,
        quantityType: validatedData.quantityType,
        quantityValue: validatedData.quantityValue,
        unit: validatedData.unit,
        expiryDate: validatedData.expiryDate ? new Date(validatedData.expiryDate) : null,
        lastTouchedById: user.id,
      },
      include: {
        addedBy: { select: { id: true, name: true } },
        lastTouchedBy: { select: { id: true, name: true } },
        usedUpBy: { select: { id: true, name: true } },
      },
    });

    // 5. Broadcast real-time update
    broadcastUpdate('update', updatedItem);

    return NextResponse.json(updatedItem);
  } catch (error) {
    console.error('PUT /api/items/[id] error:', error);
    return NextResponse.json(
      { error: 'Failed to update inventory item.' },
      { status: 500 }
    );
  }
}

// DELETE /api/items/[id] - Delete an item
export async function DELETE(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    // 1. Authenticate user
    const user = await validateRequestUser(req);
    if (!user) {
      return NextResponse.json(
        { error: 'Unauthorized. Please log in first.' },
        { status: 401 }
      );
    }

    // 2. Check if item exists
    const existingItem = await prisma.item.findUnique({
      where: { id },
    });

    if (!existingItem) {
      return NextResponse.json(
        { error: 'Item not found.' },
        { status: 404 }
      );
    }

    // 3. Delete the item
    const deletedItem = await prisma.item.delete({
      where: { id },
      include: {
        addedBy: { select: { id: true, name: true } },
        lastTouchedBy: { select: { id: true, name: true } },
        usedUpBy: { select: { id: true, name: true } },
      },
    });

    // 4. Broadcast real-time update
    broadcastUpdate('delete', deletedItem);

    return NextResponse.json(deletedItem);
  } catch (error) {
    console.error('DELETE /api/items/[id] error:', error);
    return NextResponse.json(
      { error: 'Failed to delete inventory item.' },
      { status: 500 }
    );
  }
}
